def has_be_welcoming_replica(location):
    replicas = {
        "Chicago", "Des Moines", "Toronto", "Quebec City",
        "El Camino de Santiago", "St. Padre Pio Shrine"
    }
    return location in replicas

# Example usage:
print(has_be_welcoming_replica("Toronto"))  # Output: True
print(has_be_welcoming_replica("New York")) # Output: False
